const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const text = binaryData.toString('utf8');
return [{ json: { text: text } }];

const items1 = $input.all(0); // PDFs
const item2 = $input.all()[1];  // Draft

const rawTexts = items1.map(i => i.json.text || '').join('\n---\n').substring(0, 30000);
const draftStr = item2 ? item2.json.data || item2.json.text || item2.json : '';

return [{
  json: {
    review_draft: draftStr,
    verification_context: rawTexts,
    estimated_claims: 20,
    paper_count: items1.length
  }
}];

